function refreshPaymentPanel(){
  const totals = RS.getTotals();
  const note = document.getElementById('pay-method-note');
  const checkoutBtn = document.getElementById('btn-checkout');
  if(!checkoutBtn) return;
  document.querySelectorAll('[data-pay-method]').forEach(btn=>btn.classList.toggle('active', btn.dataset.payMethod === paymentState.method));
  if(note) note.textContent = paymentState.method;
  checkoutBtn.disabled = totals.count < 1;

  // Handle inline cash calculator
  const inlineCalc = document.getElementById('cash-calc-inline');
  if (inlineCalc) {
    if (paymentState.method === 'Cash' && totals.count > 0) {
      inlineCalc.style.display = 'flex';
      const receivedInput = document.getElementById('inline-cash-received');
      if (receivedInput) {
        const currentVal = Number(receivedInput.value) || 0;
        if (!receivedInput.dataset.userInteracted || currentVal <= 0 || receivedInput.dataset.grandTotal !== String(totals.grand)) {
          receivedInput.value = totals.grand;
          receivedInput.dataset.grandTotal = totals.grand;
          delete receivedInput.dataset.userInteracted;
        }
      }
      updateInlineChange();
    } else {
      inlineCalc.style.display = 'none';
    }
  }

  // Handle inline split calculator
  const inlineSplit = document.getElementById('split-calc-compact');
  if (inlineSplit) {
    if (paymentState.method === 'Split' && totals.count > 0) {
      inlineSplit.style.display = 'flex';
      isSplitPaymentActive = true;

      const splitCash = document.getElementById('split-cash');
      const splitUpi = document.getElementById('split-upi');
      const splitCard = document.getElementById('split-card');
      const splitDue = document.getElementById('split-due');

      // Pre-fill default if all are empty/zero
      const cashVal = Number(splitCash?.value) || 0;
      const upiVal = Number(splitUpi?.value) || 0;
      const cardVal = Number(splitCard?.value) || 0;
      const dueVal = Number(splitDue?.value) || 0;
      if (cashVal === 0 && upiVal === 0 && cardVal === 0 && dueVal === 0) {
        if (splitCash) splitCash.value = totals.grand;
        if (splitUpi) splitUpi.value = '';
        if (splitCard) splitCard.value = '';
        if (splitDue) splitDue.value = '';
      }

      updateSplitChange();
    } else {
      inlineSplit.style.display = 'none';
      isSplitPaymentActive = false;
    }
  }
}

function wirePaymentPanel(){
  const methods = document.getElementById('cart-pay-methods');
  if(methods) methods.addEventListener('click', e=>{
    const btn = e.target.closest('[data-pay-method]'); if(!btn) return;
    paymentState.method = btn.dataset.payMethod;
    refreshPaymentPanel();
  });

  // Wire inline cash calculator events
  const receivedInput = document.getElementById('inline-cash-received');
  if (receivedInput) {
    receivedInput.addEventListener('input', () => {
      receivedInput.dataset.userInteracted = '1';
      updateInlineChange();
    });
  }

  // Wire inline split calculator events
  ['split-cash', 'split-upi', 'split-card', 'split-due'].forEach(id => {
    const inp = document.getElementById(id);
    if (inp) {
      inp.addEventListener('input', updateSplitChange);
    }
  });

  // Wire Quick Cash Modal button
  const quickCashBtn = document.getElementById('btn-quick-cash');
  if (quickCashBtn) {
    quickCashBtn.onclick = (e) => {
      e.preventDefault();
      e.stopPropagation();
      const totals = RS.getTotals();
      const receivedInput = document.getElementById('inline-cash-received');
      const currentReceived = receivedInput ? (Number(receivedInput.value) || 0) : totals.grand;

      RSModal.open({
        title: 'Quick Cash Calculator',
        sub: 'Select cash denomination',
        icon: 'fa-coins',
        size: 'sm',
        body: `
          <div style="display:flex; flex-direction:column; gap:16px; font-family:var(--font-body),sans-serif; padding:10px 0;">
            <div style="background: var(--glass-2); border: 1px solid var(--stroke-2); border-radius: var(--r-md); padding: 16px; text-align: center; display: flex; flex-direction: column; gap: 8px;">
              <div style="font-size: 11px; text-transform: uppercase; color: var(--text-soft); font-weight: 700; letter-spacing: 0.05em;">Received Cash</div>
              <input type="number" id="modal-cash-received-input" class="form-input" style="font-size: 32px; font-weight: 800; color: var(--orange); margin: 0 auto; width: 100%; text-align: center; font-family: var(--font-display); background: transparent; border: none; border-bottom: 2px solid var(--stroke-2); border-radius: 0; padding: 4px;" placeholder="₹0" value="${currentReceived}">
              <div style="display: flex; justify-content: space-between; align-items: center; margin-top: 8px; background: rgba(37,211,102,0.06); border: 1px solid rgba(37,211,102,0.15); border-radius: 6px; padding: 6px 12px;">
                <span style="font-size: 11px; font-weight: 700; color: var(--text-soft);">Change Due:</span>
                <strong id="modal-cash-change" style="font-size: 18px; font-weight: 800; color: #25d366;">₹0</strong>
              </div>
            </div>
            <div style="font-size: 11px; text-transform: uppercase; color: var(--text-soft); font-weight: 700; letter-spacing: 0.05em; margin-bottom: -6px;">Tap Denominations to Add</div>
            <div style="display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px;">
              <button type="button" class="btn btn-ghost modal-den-btn" data-val="exact" style="font-size: 11px; font-weight: 700; padding: 8px 0; border: 1px solid var(--orange); color: var(--orange); border-radius: 6px; height: 38px; display: flex; align-items: center; justify-content: center; background: var(--glass-2);">Exact</button>
              <button type="button" class="btn btn-ghost modal-den-btn" data-val="10" style="font-size: 11px; padding: 8px 0; border-radius: 6px; height: 38px; display: flex; align-items: center; justify-content: center; background: var(--glass-2);">+₹10</button>
              <button type="button" class="btn btn-ghost modal-den-btn" data-val="20" style="font-size: 11px; padding: 8px 0; border-radius: 6px; height: 38px; display: flex; align-items: center; justify-content: center; background: var(--glass-2);">+₹20</button>
              <button type="button" class="btn btn-ghost modal-den-btn" data-val="50" style="font-size: 11px; padding: 8px 0; border-radius: 6px; height: 38px; display: flex; align-items: center; justify-content: center; background: var(--glass-2);">+₹50</button>
              <button type="button" class="btn btn-ghost modal-den-btn" data-val="100" style="font-size: 11px; padding: 8px 0; border-radius: 6px; height: 38px; display: flex; align-items: center; justify-content: center; background: var(--glass-2);">+₹100</button>
              <button type="button" class="btn btn-ghost modal-den-btn" data-val="200" style="font-size: 11px; padding: 8px 0; border-radius: 6px; height: 38px; display: flex; align-items: center; justify-content: center; background: var(--glass-2);">+₹200</button>
              <button type="button" class="btn btn-ghost modal-den-btn" data-val="500" style="font-size: 11px; padding: 8px 0; border-radius: 6px; height: 38px; display: flex; align-items: center; justify-content: center; background: var(--glass-2);">+₹500</button>
              <button type="button" class="btn btn-ghost modal-den-btn" data-val="2000" style="font-size: 11px; padding: 8px 0; border-radius: 6px; height: 38px; display: flex; align-items: center; justify-content: center; background: var(--glass-2);">+₹2000</button>
            </div>
          </div>
        `,
        foot: `
          <button class="btn btn-primary" id="modal-cash-done-btn" style="flex:1; background: var(--orange); border-color: var(--orange); color: #fff; font-weight:700;">Done</button>
        `,
        onMount(modal, close) {
          const modalInput = modal.querySelector('#modal-cash-received-input');
          const modalChange = modal.querySelector('#modal-cash-change');
          const doneBtn = modal.querySelector('#modal-cash-done-btn');

          function updateModalChange() {
            const val = Number(modalInput.value) || 0;
            const change = Math.max(0, val - totals.grand);
            modalChange.textContent = '₹' + change;
            if (receivedInput) {
              receivedInput.value = val;
              receivedInput.dataset.userInteracted = '1';
              updateInlineChange();
            }
          }

          updateModalChange();

          modalInput.oninput = () => {
            updateModalChange();
          };

          modal.querySelectorAll('.modal-den-btn').forEach(btn => {
            btn.onclick = () => {
              const val = btn.dataset.val;
              if (val === 'exact') {
                modalInput.value = totals.grand;
                if (receivedInput) delete receivedInput.dataset.userInteracted;
              } else {
                const increment = Number(val) || 0;
                let current = Number(modalInput.value) || 0;
                if (current === totals.grand && receivedInput && !receivedInput.dataset.userInteracted) {
                  modalInput.value = increment;
                } else {
                  modalInput.value = current + increment;
                }
              }
              updateModalChange();
            };
          });

          doneBtn.onclick = close;
        }
      });
    };
  }

  // Wire Split Payment Modal button
  const openSplitBtn = document.getElementById('btn-open-split-modal');
  if (openSplitBtn) {
    openSplitBtn.onclick = (e) => {
      e.preventDefault();
      e.stopPropagation();
      const totals = RS.getTotals();

      const splitCash = document.getElementById('split-cash');
      const splitUpi = document.getElementById('split-upi');
      const splitCard = document.getElementById('split-card');
      const splitDue = document.getElementById('split-due');

      const initialCash = splitCash ? splitCash.value : '';
      const initialUpi = splitUpi ? splitUpi.value : '';
      const initialCard = splitCard ? splitCard.value : '';
      const initialDue = splitDue ? splitDue.value : '';

      RSModal.open({
        title: 'Split Payment Calculator',
        sub: 'Specify payment splits',
        icon: 'fa-arrows-split-up-and-left',
        size: 'md',
        body: `
          <div style="display:flex; flex-direction:column; gap:16px; font-family:var(--font-body),sans-serif; padding:10px 0;">
            <div style="background: var(--glass-2); border: 1px solid var(--stroke-2); border-radius: var(--r-md); padding: 16px; text-align: center; display: flex; justify-content: space-around; align-items: center; gap: 12px;">
              <div style="display: flex; flex-direction: column; gap: 2px;">
                <span style="font-size: 11px; text-transform: uppercase; color: var(--text-soft); font-weight: 700; letter-spacing: 0.05em;">Total Bill</span>
                <strong id="modal-split-total-bill" style="font-size: 24px; font-weight: 800; color: var(--orange); font-family: var(--font-display);">₹${totals.grand}</strong>
              </div>
              <div style="height: 30px; width: 1px; background: var(--stroke-2);"></div>
              <div style="display: flex; flex-direction: column; gap: 2px;">
                <span style="font-size: 11px; text-transform: uppercase; color: var(--text-soft); font-weight: 700; letter-spacing: 0.05em;">Total Paid</span>
                <strong id="modal-split-total-paid" style="font-size: 24px; font-weight: 800; color: var(--text); font-family: var(--font-display);">₹0</strong>
              </div>
              <div style="height: 30px; width: 1px; background: var(--stroke-2);"></div>
              <div style="display: flex; flex-direction: column; gap: 2px;">
                <span style="font-size: 11px; text-transform: uppercase; color: var(--text-soft); font-weight: 700; letter-spacing: 0.05em;">Remaining</span>
                <strong id="modal-split-remaining" style="font-size: 24px; font-weight: 800; color: var(--text); font-family: var(--font-display);">₹0</strong>
              </div>
            </div>

            <div style="font-size: 11px; text-transform: uppercase; color: var(--text-soft); font-weight: 700; letter-spacing: 0.05em; margin-bottom: -6px;">Specify Payment Splits</div>

            <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 12px;">
              <div class="form-group" style="display:flex; flex-direction:column; gap:4px;">
                <label style="font-size: 11px; font-weight: 700; color: var(--text-soft); display: flex; align-items: center; gap: 4px;">
                  <i class="fa-solid fa-money-bill-wave" style="color: #25d366;"></i> Cash (₹)
                </label>
                <input type="number" id="modal-split-cash" class="form-input" style="font-size: 16px; font-weight: 700; padding: 8px 10px; margin: 0;" placeholder="0" value="${initialCash}">
              </div>
              <div class="form-group" style="display:flex; flex-direction:column; gap:4px;">
                <label style="font-size: 11px; font-weight: 700; color: var(--text-soft); display: flex; align-items: center; gap: 4px;">
                  <i class="fa-solid fa-qrcode" style="color: var(--orange);"></i> UPI (₹)
                </label>
                <input type="number" id="modal-split-upi" class="form-input" style="font-size: 16px; font-weight: 700; padding: 8px 10px; margin: 0;" placeholder="0" value="${initialUpi}">
              </div>
              <div class="form-group" style="display:flex; flex-direction:column; gap:4px;">
                <label style="font-size: 11px; font-weight: 700; color: var(--text-soft); display: flex; align-items: center; gap: 4px;">
                  <i class="fa-solid fa-credit-card" style="color: #1e90ff;"></i> Card (₹)
                </label>
                <input type="number" id="modal-split-card" class="form-input" style="font-size: 16px; font-weight: 700; padding: 8px 10px; margin: 0;" placeholder="0" value="${initialCard}">
              </div>
              <div class="form-group" style="display:flex; flex-direction:column; gap:4px;">
                <label style="font-size: 11px; font-weight: 700; color: var(--text-soft); display: flex; align-items: center; gap: 4px;">
                  <i class="fa-solid fa-clock-rotate-left" style="color: var(--red);"></i> Due (₹)
                </label>
                <input type="number" id="modal-split-due" class="form-input" style="font-size: 16px; font-weight: 700; padding: 8px 10px; margin: 0;" placeholder="0" value="${initialDue}">
              </div>
            </div>
            <div id="modal-split-error-msg" style="font-size: 12px; font-weight: 700; text-align: center; display: none;"></div>
          </div>
        `,
        foot: `
          <button class="btn btn-ghost" id="modal-split-reset" style="flex:1">Reset</button>
          <button class="btn btn-primary" id="modal-split-done" style="flex:1.5; background: var(--orange); border-color: var(--orange); color: #fff; font-weight:700;">Done</button>
        `,
        onMount(modal, close) {
          const mCash = modal.querySelector('#modal-split-cash');
          const mUpi = modal.querySelector('#modal-split-upi');
          const mCard = modal.querySelector('#modal-split-card');
          const mDue = modal.querySelector('#modal-split-due');

          const mTotalPaid = modal.querySelector('#modal-split-total-paid');
          const mRemaining = modal.querySelector('#modal-split-remaining');
          const mError = modal.querySelector('#modal-split-error-msg');

          const resetBtn = modal.querySelector('#modal-split-reset');
          const doneBtn = modal.querySelector('#modal-split-done');

          function calculateModalSplit() {
            const cash = Math.max(0, Number(mCash.value) || 0);
            const upi = Math.max(0, Number(mUpi.value) || 0);
            const card = Math.max(0, Number(mCard.value) || 0);
            const due = Math.max(0, Number(mDue.value) || 0);

            const totalPaid = cash + upi + card + due;
            const remaining = totals.grand - totalPaid;

            mTotalPaid.textContent = '₹' + totalPaid;

            if (remaining === 0) {
              mRemaining.textContent = 'Balanced!';
              mRemaining.style.color = '#25d366';
              mError.style.display = 'none';
              [mCash, mUpi, mCard, mDue].forEach(i => i.style.borderColor = '');
            } else if (remaining > 0) {
              mRemaining.textContent = '₹' + remaining;
              mRemaining.style.color = 'var(--orange)';
              mError.style.display = 'none';
              [mCash, mUpi, mCard, mDue].forEach(i => i.style.borderColor = '');
            } else {
              const overpaid = totalPaid - totals.grand;
              if (cash >= overpaid) {
                mRemaining.textContent = 'Change: ₹' + overpaid;
                mRemaining.style.color = '#25d366';
                mError.style.display = 'none';
                [mCash, mUpi, mCard, mDue].forEach(i => i.style.borderColor = '');
              } else {
                mRemaining.textContent = 'Overpaid by ₹' + overpaid;
                mRemaining.style.color = 'var(--red)';
                mError.style.display = 'block';
                mError.textContent = 'Overpayment must be paid in Cash';
                mError.style.color = 'var(--red)';
                [mCash, mUpi, mCard, mDue].forEach(i => i.style.borderColor = 'var(--red)');
              }
            }

            // Sync back to hidden inputs in the sidebar
            if (splitCash) splitCash.value = mCash.value;
            if (splitUpi) splitUpi.value = mUpi.value;
            if (splitCard) splitCard.value = mCard.value;
            if (splitDue) splitDue.value = mDue.value;

            // Trigger updateSplitChange to update sidebar's total/remaining display & checkout button state
            updateSplitChange();
          }

          // Bind event listeners to input fields
          [mCash, mUpi, mCard, mDue].forEach(inp => {
            inp.oninput = calculateModalSplit;
          });

          calculateModalSplit();

          resetBtn.onclick = () => {
            mCash.value = totals.grand;
            mUpi.value = '';
            mCard.value = '';
            mDue.value = '';
            calculateModalSplit();
          };

          doneBtn.onclick = close;
        }
      });
    };
  }

  refreshPaymentPanel();
}

