const puppeteer = require('puppeteer');
const path = require('path');

(async () => {
  console.log('=== LAUNCHING PUPPETEER COMPACT POS FLOW TEST ===');
  const browser = await puppeteer.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });
  const page = await browser.newPage();
  await page.setViewport({ width: 1400, height: 900 });

  // Stub session variables before navigation
  await page.evaluateOnNewDocument(() => {
    sessionStorage.setItem('logged_in_user', 'testcashier');
    sessionStorage.setItem('logged_in_role', 'admin');
    sessionStorage.setItem('tenant_id', 'test-tenant');
    sessionStorage.setItem('tenant_slug', 'test');
    sessionStorage.setItem('tenant_name', 'Doppio Cafe');
    sessionStorage.setItem('allowed_tabs', JSON.stringify(['pos-tab']));
  });

  page.on('pageerror', err => {
    console.error('PAGE ERROR:', err.message);
  });

  page.on('console', msg => {
    if (msg.type() === 'error') {
      console.error('PAGE CONSOLE ERROR:', msg.text());
    }
  });

  console.log('Navigating to dashboard...');
  await page.goto('http://localhost:8001/dashboard.html', { waitUntil: 'networkidle2', timeout: 30000 });
  await new Promise(r => setTimeout(r, 3000));

  // 1. Add item to cart
  console.log('Step 1: Adding item to cart...');
  const itemCard = await page.$('.pos-item-card');
  if (itemCard) {
    await itemCard.click();
  } else {
    console.log('No item cards found on page, adding manually via JS...');
    await page.evaluate(() => {
      if (window.RS && window.RS.addToCart) {
        window.RS.addToCart(1);
      }
    });
  }
  await new Promise(r => setTimeout(r, 1000));

  // Get total bill amount
  const cartTotal = await page.evaluate(() => {
    const el = document.getElementById('t-grand');
    return el ? parseFloat(el.textContent.replace(/[^\d.]/g, '')) || 0 : 0;
  });
  console.log(`Cart total: ₹${cartTotal}`);
  if (cartTotal <= 0) {
    throw new Error('Cart total is 0 or element not found!');
  }

  // 2. Verify sidebar payment selectors are present
  console.log('Step 2: Verifying sidebar payment selectors...');
  const selectorsExist = await page.evaluate(() => {
    const cashBtn = document.querySelector('[data-pay-method="Cash"]');
    const splitBtn = document.querySelector('[data-pay-method="Split"]');
    const checkoutBtn = document.getElementById('btn-checkout');
    return !!(cashBtn && splitBtn && checkoutBtn);
  });
  console.log(`Sidebar payment selectors exist: ${selectorsExist}`);
  if (!selectorsExist) {
    throw new Error('Required sidebar payment selectors not found in DOM!');
  }

  // 3. Verify toggling Cash
  console.log('Step 3: Verifying Cash selector view toggle...');
  await page.click('[data-pay-method="Cash"]');
  await new Promise(r => setTimeout(r, 300));

  const cashViewVisible = await page.evaluate(() => {
    const inlineCalc = document.getElementById('cash-calc-inline');
    return inlineCalc && inlineCalc.style.display !== 'none';
  });
  console.log(`Cash panel is visible: ${cashViewVisible}`);
  if (!cashViewVisible) {
    throw new Error('Cash inline calculator not shown when Cash is selected!');
  }

  // 4. Verify toggling Split
  console.log('Step 4: Verifying Split selector view toggle...');
  await page.click('[data-pay-method="Split"]');
  await new Promise(r => setTimeout(r, 300));

  const splitViewVisible = await page.evaluate(() => {
    const inlineSplit = document.getElementById('split-calc-compact');
    return inlineSplit && inlineSplit.style.display !== 'none';
  });
  console.log(`Split panel is visible: ${splitViewVisible}`);
  if (!splitViewVisible) {
    throw new Error('Split compact panel not shown when Split is selected!');
  }

  // 5. Verify toggling back to Cash and opening Quick Cash Modal
  console.log('Step 5: Testing Quick Cash Modal...');
  await page.click('[data-pay-method="Cash"]');
  await new Promise(r => setTimeout(r, 300));

  // Click quick cash coins button
  console.log('Clicking coins button...');
  await page.click('#btn-quick-cash');
  await new Promise(r => setTimeout(r, 800));

  // Check if RSModal is open
  const cashModalOpen = await page.evaluate(() => {
    const modalTitle = document.querySelector('.rs-modal h3');
    return modalTitle && modalTitle.textContent === 'Quick Cash Calculator';
  });
  console.log(`Quick Cash Modal is open: ${cashModalOpen}`);
  if (!cashModalOpen) {
    throw new Error('Quick Cash Modal failed to open!');
  }

  // Click exact amount button in modal
  console.log('Clicking Exact button in modal...');
  await page.evaluate(() => {
    const exactBtn = Array.from(document.querySelectorAll('.modal-den-btn'))
      .find(b => b.getAttribute('data-val') === 'exact');
    if (exactBtn) exactBtn.click();
  });
  await new Promise(r => setTimeout(r, 300));

  // Verify modal cash matches cart total
  const modalCashVal = await page.evaluate(() => {
    const inp = document.getElementById('modal-cash-received-input');
    return inp ? parseFloat(inp.value) || 0 : 0;
  });
  console.log(`Modal cash received: ₹${modalCashVal}`);
  if (modalCashVal !== cartTotal) {
    throw new Error(`Expected modal received value to match cart total: expected ${cartTotal}, got ${modalCashVal}`);
  }

  // Verify change in modal is 0
  const modalChangeVal = await page.evaluate(() => {
    const el = document.getElementById('modal-cash-change');
    return el ? parseFloat(el.textContent.replace(/[^\d.]/g, '')) || 0 : -99;
  });
  console.log(`Modal change: ₹${modalChangeVal}`);
  if (modalChangeVal !== 0) {
    throw new Error(`Expected change in modal to be 0 for exact payment. Got ${modalChangeVal}`);
  }

  // Tap +50 denomination in modal
  console.log('Tapping +₹50 denomination in modal...');
  await page.evaluate(() => {
    const den50 = Array.from(document.querySelectorAll('.modal-den-btn'))
      .find(b => b.getAttribute('data-val') === '50');
    if (den50) den50.click();
  });
  await new Promise(r => setTimeout(r, 300));

  // Verify modal cash matches cart total + 50
  const modalCashVal2 = await page.evaluate(() => {
    const inp = document.getElementById('modal-cash-received-input');
    return inp ? parseFloat(inp.value) || 0 : 0;
  });
  console.log(`Modal cash received after +50: ₹${modalCashVal2}`);
  if (modalCashVal2 !== cartTotal + 50) {
    throw new Error(`Expected modal received value to be ${cartTotal + 50}, got ${modalCashVal2}`);
  }

  // Verify change in modal is 50
  const modalChangeVal2 = await page.evaluate(() => {
    const el = document.getElementById('modal-cash-change');
    return el ? parseFloat(el.textContent.replace(/[^\d.]/g, '')) || 0 : -99;
  });
  console.log(`Modal change after +50: ₹${modalChangeVal2}`);
  if (modalChangeVal2 !== 50) {
    throw new Error(`Expected change in modal to be 50. Got ${modalChangeVal2}`);
  }

  // Close Quick Cash Modal
  console.log('Closing Quick Cash Modal...');
  await page.click('#modal-cash-done-btn');
  await new Promise(r => setTimeout(r, 500));

  // Verify modal is removed
  const cashModalOpenAfterClose = await page.evaluate(() => {
    const modalTitle = document.querySelector('.rs-modal h3');
    return !!(modalTitle && modalTitle.textContent === 'Quick Cash Calculator');
  });
  console.log(`Quick Cash Modal still open: ${cashModalOpenAfterClose}`);
  if (cashModalOpenAfterClose) {
    throw new Error('Quick Cash Modal failed to close!');
  }

  // Verify received cash in sidebar matches what we set in modal (cartTotal + 50)
  const sidebarReceivedVal = await page.evaluate(() => {
    const inp = document.getElementById('inline-cash-received');
    return inp ? parseFloat(inp.value) || 0 : 0;
  });
  console.log(`Sidebar received cash: ₹${sidebarReceivedVal}`);
  if (sidebarReceivedVal !== cartTotal + 50) {
    throw new Error(`Expected sidebar received cash to match modal value: expected ${cartTotal + 50}, got ${sidebarReceivedVal}`);
  }

  // Verify change in sidebar matches modal value (50)
  const sidebarChangeVal = await page.evaluate(() => {
    const el = document.getElementById('inline-cash-change');
    return el ? parseFloat(el.textContent.replace(/[^\d.]/g, '')) || 0 : -99;
  });
  console.log(`Sidebar change: ₹${sidebarChangeVal}`);
  if (sidebarChangeVal !== 50) {
    throw new Error(`Expected sidebar change to match modal change: expected 50, got ${sidebarChangeVal}`);
  }

  // 6. Test Split Payment Modal
  console.log('Step 6: Testing Split Payment Modal...');
  await page.click('[data-pay-method="Split"]');
  await new Promise(r => setTimeout(r, 300));

  // Click configure split button
  console.log('Clicking configure split button...');
  await page.click('#btn-open-split-modal');
  await new Promise(r => setTimeout(r, 800));

  // Check if RSModal is open
  const splitModalOpen = await page.evaluate(() => {
    const modalTitle = document.querySelector('.rs-modal h3');
    return modalTitle && modalTitle.textContent === 'Split Payment Calculator';
  });
  console.log(`Split Payment Modal is open: ${splitModalOpen}`);
  if (!splitModalOpen) {
    throw new Error('Split Payment Modal failed to open!');
  }

  // Set split splits: Card = 100, UPI = remaining
  console.log('Configuring splits in modal...');
  await page.evaluate((totalBill) => {
    const cardInput = document.getElementById('modal-split-card');
    const upiInput = document.getElementById('modal-split-upi');
    const cashInput = document.getElementById('modal-split-cash');
    if (cashInput) cashInput.value = ''; // clear default cash
    if (cardInput) {
      cardInput.value = '100';
      cardInput.dispatchEvent(new Event('input'));
    }
    if (upiInput) {
      upiInput.value = String(totalBill - 100);
      upiInput.dispatchEvent(new Event('input'));
    }
  }, cartTotal);
  await new Promise(r => setTimeout(r, 500));

  // Verify balanced in modal
  const splitModalRemaining = await page.evaluate(() => {
    const el = document.getElementById('modal-split-remaining');
    return el ? el.textContent : '';
  });
  console.log(`Split modal remaining text: ${splitModalRemaining}`);
  if (splitModalRemaining !== 'Balanced!') {
    throw new Error(`Expected split modal to show 'Balanced!', got '${splitModalRemaining}'`);
  }

  // Close Split Modal
  console.log('Closing Split Modal...');
  await page.click('#modal-split-done');
  await new Promise(r => setTimeout(r, 500));

  // Verify modal is removed
  const splitModalOpenAfterClose = await page.evaluate(() => {
    const modalTitle = document.querySelector('.rs-modal h3');
    return !!(modalTitle && modalTitle.textContent === 'Split Payment Calculator');
  });
  console.log(`Split Modal still open: ${splitModalOpenAfterClose}`);
  if (splitModalOpenAfterClose) {
    throw new Error('Split Payment Modal failed to close!');
  }

  // Verify split status row values in sidebar
  const sidebarSplitRemainingText = await page.evaluate(() => document.getElementById('split-status-text')?.textContent);
  const sidebarSplitTotalText = await page.evaluate(() => document.getElementById('split-total-text')?.textContent);
  console.log(`Sidebar Split Remaining: ${sidebarSplitRemainingText}, Sidebar Split Total: ${sidebarSplitTotalText}`);
  if (sidebarSplitRemainingText !== 'Balanced!') {
    throw new Error(`Expected sidebar remaining text to show 'Balanced!', got '${sidebarSplitRemainingText}'`);
  }

  // Verify hidden inputs in sidebar have correct values
  const hiddenCash = await page.evaluate(() => document.getElementById('split-cash')?.value);
  const hiddenCard = await page.evaluate(() => document.getElementById('split-card')?.value);
  const hiddenUpi = await page.evaluate(() => document.getElementById('split-upi')?.value);
  const hiddenDue = await page.evaluate(() => document.getElementById('split-due')?.value);
  console.log(`Hidden inputs values - Cash: "${hiddenCash}", Card: "${hiddenCard}", UPI: "${hiddenUpi}", Due: "${hiddenDue}"`);
  if (hiddenCard !== '100' || parseFloat(hiddenUpi) !== cartTotal - 100) {
    throw new Error(`Expected hidden card input to be 100 and upi to be ${cartTotal - 100}!`);
  }

  // 7. Verify Checkout execution
  console.log('Step 7: Finalizing order and printing bill...');
  // Click Print & Pay
  await page.click('#btn-checkout');
  await new Promise(r => setTimeout(r, 1500));

  // Verify checkout modal closed and cart is cleared
  const cartItemCount = await page.evaluate(() => {
    const list = document.getElementById('cart-items');
    return list ? list.children.length : -99;
  });
  console.log(`Items in cart post-checkout: ${cartItemCount}`);
  if (cartItemCount !== 0) {
    throw new Error(`Expected cart items list to be empty post-checkout, got count of ${cartItemCount}`);
  }

  console.log('=== ALL NEW COMPACT POS FLOW TESTS PASSED SUCCESSFULLY! ===');
  await browser.close();
  process.exit(0);
})().catch(err => {
  console.error('\n=== TEST RUN FAILED ===');
  console.error(err);
  process.exit(1);
});

