      `,
      onMount(modal, close) {
        const mCash = modal.querySelector('#modal-split-cash');
        const mUpi = modal.querySelector('#modal-split-upi');
        const mCard = modal.querySelector('#modal-split-card');
        const mDue = modal.querySelector('#modal-split-due');

        const mTotalPaid = modal.querySelector('#modal-split-total-paid');
        const mRemaining = modal.querySelector('#modal-split-remaining');
        const mError = modal.querySelector('#modal-split-error-msg');

        const resetBtn = modal.querySelector('#modal-split-reset');
        const doneBtn = modal.querySelector('#modal-split-done');

