          const cash = Math.max(0, Number(mCash.value) || 0);
          const upi = Math.max(0, Number(mUpi.value) || 0);
          const card = Math.max(0, Number(mCard.value) || 0);
          const due = Math.max(0, Number(mDue.value) || 0);

