            mRemaining.textContent = 'Balanced!';
            mRemaining.style.color = '#25d366';
            mError.style.display = 'none';
            [mCash, mUpi, mCard, mDue].forEach(i => i.style.borderColor = '');
          } else if (remaining > 0) {
            mRemaining.textContent = '₹' + remaining;
            mRemaining.style.color = 'var(--orange)';
            mError.style.display = 'none';
            [mCash, mUpi, mCard, mDue].forEach(i => i.style.borderColor = '');
          } else {
            const overpaid = totalPaid - totals.grand;
            if (cash >= overpaid) {
              mRemaining.textContent = 'Change: ₹' + overpaid;
              mRemaining.style.color = '#25d366';
              mError.style.display = 'none';
              [mCash, mUpi, mCard, mDue].forEach(i => i.style.borderColor = '');
            } else {
              mRemaining.textContent = 'Overpaid by ₹' + overpaid;
              mRemaining.style.color = 'var(--red)';
              mError.style.display = 'block';
              mError.textContent = 'Overpayment must be paid in Cash';
              mError.style.color = 'var(--red)';
              [mCash, mUpi, mCard, mDue].forEach(i => i.style.borderColor = 'var(--red)');
            }
          }

          // Sync back to hidden inputs in the sidebar
          if (splitCash) splitCash.value = mCash.value;
          if (splitUpi) splitUpi.value = mUpi.value;
          if (splitCard) splitCard.value = mCard.value;
          if (splitDue) splitDue.value = mDue.value;

          // Trigger updateSplitChange to update sidebar's total/remaining display & checkout button state
          updateSplitChange();
        }

        // Bind event listeners to input fields
        [mCash, mUpi, mCard, mDue].forEach(inp => {
          inp.oninput = calculateModalSplit;
        });

