  height: 38px;
  box-sizing: border-box;
}
.pos-sort-select:hover {
  border-color: var(--orange);
}

/* Custom Select Dropdown Widget */
.custom-dropdown-widget {
  position: relative;
  display: inline-block;
  min-width: 140px;
}
.custom-dropdown-widget .dropdown-trigger {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 16px;
  border-radius: var(--r-pill);
  background: var(--panel);
  border: 1px solid var(--stroke-2);
  color: var(--text-soft);
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  height: 38px;
  box-sizing: border-box;
  transition: var(--t);
  user-select: none;
}
.custom-dropdown-widget .dropdown-trigger:hover,
.custom-dropdown-widget.active .dropdown-trigger {
  border-color: var(--orange);
  color: var(--text);
  background: var(--glass-2);
}
.custom-dropdown-widget .dropdown-trigger i.caret {
  transition: transform 0.2s ease;
  margin-left: 8px;
  color: var(--text-mute);
}
.custom-dropdown-widget.active .dropdown-trigger i.caret {
  transform: rotate(180deg);
}
.custom-dropdown-widget .dropdown-menu {
  position: absolute;
  top: calc(100% + 6px);
  left: 0;
  width: 100%;
  min-width: 190px;
  background: var(--panel-solid);
  border: 1px solid var(--stroke-2);
  border-radius: var(--r-md);
  box-shadow: var(--shadow-lg);
  padding: 6px;
  z-index: 1100;
  display: none;
  flex-direction: column;
  gap: 2px;
  list-style: none;
  margin: 0;
  box-sizing: border-box;
  animation: dropdownFade 0.18s var(--ease);
}
.custom-dropdown-widget.active .dropdown-menu {
  display: flex;
}
.custom-dropdown-widget .dropdown-item {
  padding: 8px 12px;
  font-size: 13.5px;
  font-weight: 500;
  color: var(--text-soft);
  border-radius: var(--r-sm);
  cursor: pointer;
  transition: var(--t);
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.custom-dropdown-widget .dropdown-item:hover {
  background: var(--orange-tint);
  color: var(--orange);
}
.custom-dropdown-widget .dropdown-item.active {
  background: var(--orange);
  color: #fff;
  font-weight: 600;
}

@keyframes dropdownFade {
  from { opacity: 0; transform: translateY(-8px); }
  to { opacity: 1; transform: translateY(0); }
}

