/* ============================================================
   PAYMENT SIDE DRAWERS  (Cash = left, Split = right)
   ============================================================ */

/* --- Cart-width variable used to position drawers --- */
:root { --cart-w: 372px; }

.cpay-side-drawer {
  position: fixed;
  /* vertically: sit above the payment row – near bottom of viewport */
  bottom: 120px;
  width: 240px;
  max-height: 420px;
  overflow-y: auto;
  z-index: 300;
  border-radius: var(--r-md);
  background: var(--panel);
  border: 1px solid var(--stroke-2);
  box-shadow: 0 8px 32px rgba(0,0,0,.22);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  /* hidden by default – translated off-screen */
  opacity: 0;
  pointer-events: none;
  transition: transform .28s cubic-bezier(.4,0,.2,1), opacity .22s ease;
}

/* LEFT drawer – Cash */
.cpay-drawer-left {
  right: calc(var(--cart-w) + 6px); /* just outside the left edge of cart */
  transform: translateX(30px);
}
.cpay-drawer-left.csd-open {
  transform: translateX(0);
  opacity: 1;
  pointer-events: all;
}

/* RIGHT drawer – Split */
.cpay-drawer-right {
  right: -250px; /* hidden to the right */
  transform: translateX(0);
}
.cpay-drawer-right.csd-open {
  right: calc(-1px); /* peek out just right of cart */
  transform: translateX(0);
  opacity: 1;
  pointer-events: all;
}

/* -- Actually let's use transform for right drawer too -- */
.cpay-drawer-right {
  right: -4px;
  transform: translateX(100%);
}
.cpay-drawer-right.csd-open {
  transform: translateX(100%);  /* keep it just off the right edge of cart */
  opacity: 1;
  pointer-events: all;
}

/* Drawer header */
.csd-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 12px 8px;
  border-bottom: 1px solid var(--stroke-2);
  gap: 8px;
}
.csd-title {
  font-size: 12px;
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: .04em;
  color: var(--text-soft);
  display: flex;
  align-items: center;
  gap: 6px;
}
.csd-close {
  background: none;
  border: none;
  font-size: 18px;
  line-height: 1;
  font-weight: 700;
  color: var(--text-mute);
  cursor: pointer;
  padding: 0 2px;
  transition: color .15s;
  flex-shrink: 0;
}
.csd-close:hover { color: var(--red); }

/* Drawer body */
.csd-body {
  padding: 10px 12px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

/* Label */
.csd-label {
  font-size: 10px;
  font-weight: 700;
  color: var(--text-soft);
  text-transform: uppercase;
  letter-spacing: .04em;
}

/* Cash: received row */
.csd-row {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.csd-input {
  width: 100% !important;
  height: 36px !important;
  font-size: 15px !important;
  font-weight: 700 !important;
  text-align: right !important;
  padding: 4px 10px !important;
}

