}
.csd-change-amt {
  font-size: 16px;
  font-weight: 800;
  color: #25d366;
}

/* Denomination grid */
.csd-den-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 5px;
}
.csd-den-btn {
  height: 30px;
  font-size: 11px;
  font-weight: 700;
  border: 1px solid var(--stroke-2);
  background: var(--glass-2);
  color: var(--text-soft);
  border-radius: var(--r-xs);
  cursor: pointer;
  transition: background .12s, color .12s, border-color .12s;
}
.csd-den-btn:hover {
  background: var(--orange-tint);
  color: var(--orange);
  border-color: rgba(255,79,0,.4);
}
.csd-den-exact {
  background: rgba(255,79,0,.08);
  border-color: rgba(255,79,0,.4);
  color: var(--orange);
  grid-column: 1 / -1;
}
.csd-den-exact:hover {
  background: var(--orange-tint);
}
.csd-den-clear {
  border-color: rgba(255,69,58,.4);
  color: var(--red);
  background: rgba(255,69,58,.07);
  grid-column: 1 / -1;
}
.csd-den-clear:hover {
  background: rgba(255,69,58,.14);
}

/* Split: individual method rows */
.csd-split-field {
  display: grid;
  grid-template-columns: 30px 44px 1fr;
  align-items: center;
  gap: 6px;
  border: 1px solid var(--stroke-2);
  border-radius: var(--r-sm);
  padding: 4px 8px;
  background: var(--glass-2);
}
.csd-split-icon {
  width: 26px;
  height: 26px;
  border-radius: var(--r-xs);
  display: grid;
  place-items: center;
  font-size: 12px;
  flex-shrink: 0;
}
.csd-split-field .csd-input {
  height: 28px !important;
  font-size: 13px !important;
  padding: 2px 6px !important;
  border: 1px solid var(--stroke-2) !important;
  border-radius: var(--r-xs) !important;
  background: var(--panel) !important;
  text-align: right !important;
}

/* Split: balance status footer */
.csd-split-status {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: var(--glass-2);
  border: 1px solid var(--stroke-2);
  border-radius: var(--r-sm);
  padding: 6px 10px;
  font-size: 11px;
}
.csd-split-remaining { font-weight: 700; color: var(--text-soft); }
.csd-split-paid { font-size: 13px; font-weight: 800; color: var(--orange); }

/* On small screens where there's no room, drawers go above the methods row inline */
@media (max-width: 1024px) {
  .cpay-side-drawer {
    position: fixed;
    bottom: 80px;
    right: 8px !important;
    left: 8px !important;
    width: auto !important;
    transform: translateY(20px) !important;
    border-radius: var(--r-md);
  }
  .cpay-side-drawer.csd-open {
    transform: translateY(0) !important;
  }
}

