/* LEFT drawer – Cash: starts nudged to the right (tucked under cart edge), slides left into view */
.cpay-drawer-left {
  right: calc(var(--cart-w) + 8px);
  transform: translateX(20px);
}
.cpay-drawer-left.csd-open {
  transform: translateX(0);
  opacity: 1;
  pointer-events: all;
}

/* RIGHT drawer – Split: starts off-screen to the right, slides left into its position beside the cart */
.cpay-drawer-right {
  right: -260px;   /* off-screen right */
  transform: translateX(0);
}
.cpay-drawer-right.csd-open {
  right: -248px;   /* sits just to the right of the cart (outside) */
  opacity: 1;
  pointer-events: all;
}

