// ─── Side Drawer helpers ────────────────────────────────────────────────
function positionDrawers() {
  // Find the cart element to anchor the drawers beside it
  const cart = document.querySelector('.pos-cart');
  if (!cart) return;
  const rect = cart.getBoundingClientRect();
  const vw = window.innerWidth;
  const cashDrawer  = document.getElementById('cash-drawer');
  const splitDrawer = document.getElementById('split-drawer');

  if (cashDrawer) {
    // Cash drawer: left side of the cart (slides in from the left)
    const leftPos = rect.left - 252; // 240px wide + 12px gap
    if (leftPos >= 0) {
      cashDrawer.style.left  = leftPos + 'px';
      cashDrawer.style.right = 'auto';
      cashDrawer.style.bottom = (vw < 1024) ? '80px' : '120px';
      cashDrawer.style.width = '240px';
    } else {
      // Not enough room on left – centre on screen
      cashDrawer.style.left  = '50%';
      cashDrawer.style.right = 'auto';
      cashDrawer.style.transform = cashDrawer.classList.contains('csd-open')
        ? 'translateX(-50%)' : 'translateX(-50%) translateY(20px)';
      cashDrawer.style.bottom = '80px';
    }
  }
  if (splitDrawer) {
    // Split drawer: right side of the cart (slides in from the right)
    const rightPos = vw - rect.right - 252;
    if (rect.right + 12 + 240 <= vw) {
      splitDrawer.style.left  = (rect.right + 12) + 'px';
      splitDrawer.style.right = 'auto';
      splitDrawer.style.bottom = (vw < 1024) ? '80px' : '120px';
      splitDrawer.style.width = '240px';
    } else {
      splitDrawer.style.left  = '50%';
      splitDrawer.style.right = 'auto';
      splitDrawer.style.transform = splitDrawer.classList.contains('csd-open')
        ? 'translateX(-50%)' : 'translateX(-50%) translateY(20px)';
      splitDrawer.style.bottom = '80px';
    }
  }
}

