args.ReplacementContent:
/* ============================================================
   PAYMENT SIDE DRAWERS  (Cash = left of cart, Split = right of cart)
   ============================================================ */

:root { --cart-w: 372px; }

.cpay-side-drawer {
  position: fixed;
  bottom: 140px;
  width: 250px;
  max-height: 440px;
  overflow-y: auto;
  z-index: 9999;
  border-radius: var(--r-md);
  background: var(--panel);
  border: 1px solid var(--stroke-2);
  box-shadow: 0 12px 40px rgba(0,0,0,.28), 0 2px 8px rgba(0,0,0,.12);
  /* hidden by default */
  opacity: 0;
  visibility: hidden;
  pointer-events: none;
  transition: transform .3s cubic-bezier(.4,0,.2,1),
              opacity .25s ease,
              visibility 0s linear .3s;
}

/* ---- Cash drawer: to the LEFT of the cart ---- */
.cpay-drawer-left {
  right: calc(var(--cart-w) + 20px); /* left of the cart panel */
  transform: translateX(16px);       /* start slightly to the right, slide left */
}
.cpay-drawer-left.csd-open {
  transform: translateX(0);
  opacity: 1;
  visibility: visible;
  pointer-events: all;
  transition: transform .3s cubic-bezier(.4,0,.2,1),
              opacity .25s ease,
              visibility 0s linear 0s;
}

/* ---- Split drawer: to the RIGHT of the cart ---- */
.cpay-drawer-right {
  right: calc(-1 * (250px + 20px)); /* start off-screen to the right */
  transform: translateX(0);
}
.cpay-drawer-right.csd-open {
  right: 0;                          /* flush with right edge of viewport */
  transform: translateX(0);
  opacity: 1;
  visibility: visible;
  pointer-events: all;
  transition: right .3s cubic-bezier(.4,0,.2,1),
              opacity .25s ease,
              visibility 0s linear 0s;
}

/* On narrow screens both drawers centre above the payment bar */
@media (max-width: 1100px) {
  .cpay-side-drawer {
    left: 50% !important;
    right: auto !important;
    bottom: 80px;
    width: min(90vw, 320px);
    transform: translateX(-50%) translateY(16px);
  }
  .cpay-side-drawer.csd-open {
    transform: translateX(-50%) translateY(0) !important;
    opacity: 1;
    visibility: visible;
    pointer-events: all;
    transition: transform .3s cubic-bezier(.4,0,.2,1),
                opacity .25s ease,
                visibility 0s linear 0s;
  }
}

