   Cash  = floating panel to the LEFT  of the cart
   Split = floating panel to the RIGHT of the cart
   ============================================================ */

:root { --cart-w: 372px; }

/* Base state – HIDDEN */
.cpay-side-drawer {
  position: fixed;
  bottom: 160px;
  width: 260px;
  max-height: 460px;
  overflow-y: auto;
  z-index: 9999;
  border-radius: 14px;
  background: var(--panel);
  border: 1px solid var(--stroke-2);
  box-shadow: 0 16px 48px rgba(0,0,0,.30), 0 2px 8px rgba(0,0,0,.10);
  opacity: 0;
  visibility: hidden;
  pointer-events: none;
  /* slide-up + fade animation */
  transform: translateY(18px);
  transition: transform .28s cubic-bezier(.34,1.56,.64,1),
              opacity .22s ease,
              visibility 0s .28s;
}

/* OPEN state */
.cpay-side-drawer.csd-open {
  opacity: 1;
  visibility: visible;
  pointer-events: all;
  transform: translateY(0);
  transition: transform .28s cubic-bezier(.34,1.56,.64,1),
              opacity .22s ease,
              visibility 0s 0s;
}

/* Cash drawer – LEFT of cart */
.cpay-drawer-left {
  right: calc(var(--cart-w) + 16px);
}

/* Split drawer – RIGHT of cart (overlaps the right scroll area, not the cart) */
.cpay-drawer-right {
  right: 8px;
}

