@media (max-width: 1100px) {
  .cpay-drawer-left,
  .cpay-drawer-right {
    left: 50%;
    right: auto;
    bottom: 96px;
    width: min(92vw, 320px);
    transform: translateX(-50%) translateY(18px);
  }
  .cpay-drawer-left.csd-open,
  .cpay-drawer-right.csd-open {
    transform: translateX(-50%) translateY(0);
  }
}

