const puppeteer = require('puppeteer');

(async () => {
  console.log('=== STARTING POS ERROR CHECK TEST ===');
  const browser = await puppeteer.launch({
    headless: true,
    executablePath: 'C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe',
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });
  const page = await browser.newPage();
  await page.setViewport({ width: 1400, height: 900 });

  // Stub session variables and window.fetch before navigation
  await page.evaluateOnNewDocument(() => {
    sessionStorage.setItem('tenant_session_token', 'mock-session-token');
    sessionStorage.setItem('logged_in_user', 'testcashier');
    sessionStorage.setItem('logged_in_role', 'admin');
    sessionStorage.setItem('tenant_id', 'test-tenant');
    sessionStorage.setItem('tenant_slug', 'test');
    sessionStorage.setItem('tenant_name', 'Doppio Cafe');
    sessionStorage.setItem('allowed_tabs', JSON.stringify(['pos-tab']));

    window.confirm = () => true;
    window.alert = () => {};
    window.prompt = () => null;

    // Mock API
    const originalFetch = window.fetch;
    window.fetch = async (url, options) => {
      const urlStr = String(url);
      if (urlStr.includes('tenant-access')) {
        const body = JSON.parse(options?.body || '{}');
        if (body.action === 'validate_session') {
          return new Response(JSON.stringify({
            session: {
              session_token: 'mock-session-token',
              tenant_id: 'test-tenant',
              tenant_slug: 'test',
              tenant_name: 'Doppio Cafe',
              username: 'testcashier',
              role: 'admin',
              display_name: 'Test Cashier',
              allowed_tabs: ['pos-tab']
            }
          }), { status: 200, headers: { 'Content-Type': 'application/json' } });
        }
      }
      if (urlStr.includes('tenant-data')) {
        const body = JSON.parse(options?.body || '{}');
        if (body.operation === 'select') {
          if (body.table === 'doppio_menu_items') {
            return new Response(JSON.stringify({
              data: [
                { id: 'item-1', name: 'Espresso', price: 120, category: 'Coffee', status: 'available' },
                { id: 'item-2', name: 'Croissant', price: 150, category: 'Bakery', status: 'available' }
              ]
            }), { status: 200, headers: { 'Content-Type': 'application/json' } });
          }
          return new Response(JSON.stringify({ data: [] }), { status: 200, headers: { 'Content-Type': 'application/json' } });
        }
        return new Response(JSON.stringify({ data: body.data || {} }), { status: 200, headers: { 'Content-Type': 'application/json' } });
      }
      try {
        return await originalFetch(url, options);
      } catch (e) {
        return new Response(JSON.stringify({ error: e.message }), { status: 500 });
      }
    };
  });

  page.on('pageerror', err => {
    console.error('PAGE ERROR EXCEPTION:', err.message, err.stack);
  });

  page.on('console', msg => {
    console.log(`CONSOLE [${msg.type()}]:`, msg.text());
  });

  await page.goto('http://localhost:8001/dashboard.html#pos-tab', { waitUntil: 'load', timeout: 10000 });
  await new Promise(r => setTimeout(r, 2000));

  // Add item to cart
  await page.evaluate(() => {
    if (window.RS && window.RS.addToCart) {
      window.RS.addToCart({ id: 'item-1', name: 'Espresso', price: 120 });
    }
  });
  await new Promise(r => setTimeout(r, 500));

  // Click the Split button
  console.log('Triggering Split drawer click...');
  await page.evaluate(() => {
    const btn = document.querySelector('[data-pay-method="Split"]');
    if (btn) btn.click();
  });
  await new Promise(r => setTimeout(r, 1000));

  // Check if error banner exists and get its content
  const errorBannerContent = await page.evaluate(() => {
    const banner = document.getElementById('debug-error-banner');
    return banner ? banner.innerHTML : null;
  });
  console.log('Error banner content:', errorBannerContent);

  await browser.close();
  console.log('=== DONE ===');
})().catch(err => {
  console.error(err);
});

